            <table className="table table-sm">
              <thead>
                <tr>
                  <th>Name</th>
                  <th>Code</th>
                  <th>Owner</th>
                  <th>Status</th>
                  <th></th>
                </tr>
              </thead>
              <tbody>
                {centers.length ? (
                  centers.map((row) => (
                    <tr key={row.id}>
                      <td>{row.name}</td>
                      <td>{row.code}</td>
