                <div className="d-flex justify-content-between">
                  <span>High</span>
                  <span>{summary.incidents.high}</span>
                </div>
                <div className="d-flex justify-content-between">
                  <span>Medium</span>
                  <span>{summary.incidents.medium}</span>
                </div>
                <div className="d-flex justify-content-between">
                  <span>Low</span>
                  <span>{summary.incidents.low}</span>
