import { useEffect, useState } from "react";

export default function AffairsSOS(){

  const [alerts,setAlerts] = useState([]);
  const [msg,setMsg] = useState("");

  const loadAlerts = async ()=>{
    let res = await fetch("http://localhost/SmartCampus/backend/get_sos.php");
    let data = await res.json();

    console.log("SOS FETCH", data);

    if(data.status){
      setAlerts(data.alerts || []);   // 👈 IMPORTANT (prevents undefined)
      setMsg("");
    } else {
      setAlerts([]);
      setMsg("No SOS Alerts Found");
    }
  };

  useEffect(()=>{
    loadAlerts();

    const i = setInterval(loadAlerts, 5000);
    return ()=>clearInterval(i);
  },[]);

  return(
    <div className="container mt-4">
      <div className="card p-4 shadow">

        <h3>🚨 Live SOS Alerts</h3>
        <p className="text-danger">
          System checks every 5 seconds.
        </p>

        {msg && <p className="text-danger">{msg}</p>}

        <table className="table table-bordered">
          <thead>
            <tr>
              <th>Student</th>
              <th>Message</th>
              <th>Location</th>
              <th>Photo</th>
              <th>Time</th>
            </tr>
          </thead>

          <tbody>

            {alerts.map((s,i)=>(
              <tr key={i}>
                <td>{s.name} ({s.reg_no})</td>
                <td>{s.message}</td>

                <td>
                  <a target="_blank"
                     href={`https://www.google.com/maps?q=${s.latitude},${s.longitude}`}>
                     View Location
                  </a>
                </td>

                <td>
                  {s.photo
                    ? <a target="_blank"
                         href={`http://localhost/SmartCampus/uploads/${s.photo}`}>
                        View Photo
                      </a>
                    : "No Photo"}
                </td>

                <td>{s.created_at}</td>
              </tr>
            ))}

            {alerts.length === 0 && (
              <tr>
                <td colSpan={5} className="text-center">
                  No Active SOS Alerts
                </td>
              </tr>
            )}

          </tbody>
        </table>

      </div>
    </div>
  );
}

import { useEffect, useState } from "react";

export default function AssignHOD(){

  const [teachers, setTeachers] = useState([]);
  const [loading, setLoading] = useState(true);
  const [msg, setMsg] = useState("");

  // 🔹 Load teachers
  const loadTeachers = async () => {
    try{
      const res = await fetch(
        "http://localhost/SmartCampus/backend/get_teachers.php"
      );
      const data = await res.json();   // ✅ data defined HERE

      if(data.status){
        setTeachers(data.teachers);
      }else{
        setMsg("❌ Failed to load teachers");
      }

    }catch(err){
      console.error(err);
      setMsg("❌ Server error");
    }

    setLoading(false);
  };

  // 🔹 Assign HOD
  const assignHOD = async (teacher_id, dept) => {
    try{
      const res = await fetch(
        "http://localhost/SmartCampus/backend/assign_hod.php",
        {
          method: "POST",
          headers:{ "Content-Type":"application/json" },
          body: JSON.stringify({ teacher_id, dept })
        }
      );

      const data = await res.json();

      if(data.status){
        setMsg("✅ HOD Assigned Successfully");
        loadTeachers(); // 🔄 refresh list
      }else{
        setMsg("❌ " + data.message);
      }

    }catch(err){
      console.error(err);
      setMsg("❌ Assign failed");
    }
  };

  useEffect(()=>{
    loadTeachers();
  },[]);

  return (
    <div className="container mt-4">

      <h3>Assign HOD</h3>

      {msg && <p className="fw-bold">{msg}</p>}

      {loading ? (
        <p>Loading...</p>
      ) : (
        <table className="table table-bordered mt-3">
          <thead className="table-dark">
            <tr>
              <th>Name</th>
              <th>Staff ID</th>
              <th>Department</th>
              <th>Role</th>
              <th>Action</th>
            </tr>
          </thead>

          <tbody>
  {Array.from(
    new Map(teachers.map(t => [t.id, t])).values()
  ).map((t) => (
    <tr key={t.id}>
      <td>{t.name}</td>
      <td>{t.staff_id || "-"}</td>
      <td>{t.dept}</td>

      <td>
        {String(t.is_hod) === "1" ? (
          <span className="badge bg-success">HOD</span>
        ) : (
          <span className="badge bg-secondary">Teacher</span>
        )}
      </td>

      <td>
        {String(t.is_hod) !== "1" && (
          <button
            className="btn btn-sm btn-primary"
            onClick={() => assignHOD(t.id, t.dept)}
          >
            Assign HOD
          </button>
        )}
      </td>
    </tr>
  ))}
</tbody>

        </table>
      )}

    </div>
  );
}

