import { useEffect, useState } from "react";
import { apiCall, buildUrl } from "../utils/apiClient";

export default function CoordinatorStudents() {

  const stored = JSON.parse(localStorage.getItem("user")) || {};
  const user = stored.user || stored;
  const coordinator_id =
    user?.teacher_id ||
    user?.linked_id ||
    user?.user?.linked_id ||
    user?.user?.teacher_id ||
    user?.user_id ||
    user?.id;

  const [students, setStudents] = useState([]);
  const [logoutRequests, setLogoutRequests] = useState([]);
  const [loading, setLoading] = useState(true);
  const [loadingRequests, setLoadingRequests] = useState(true);
  const [actionLoadingId, setActionLoadingId] = useState(0);
  const [search, setSearch] = useState("");

  const loadStudents = async () => {
    try {
      const data = await apiCall(
        buildUrl(`get_coordinator_students.php?coordinator_id=${coordinator_id}`)
      );

      if (data.status) {
        setStudents(data.students);
      }
    } catch (err) {
      console.error(err);
    }

    setLoading(false);
  };

  const loadLogoutRequests = async () => {
    setLoadingRequests(true);
    try {
      const data = await apiCall(
        buildUrl(`get_logout_requests.php?coordinator_id=${coordinator_id}`)
      );

      if (data?.status) {
        setLogoutRequests(data.requests || []);
      }
    } catch (error) {
      console.error(error);
    }
    setLoadingRequests(false);
  };

  const decideRequest = async (requestId, decision) => {
    setActionLoadingId(requestId);
    const data = await apiCall(buildUrl("decide_logout_request.php"), {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({
        request_id: requestId,
        decision,
        decision_note: decision === "approved" ? "Approved by coordinator" : "Rejected by coordinator"
      })
    });

    if (!data?.status) {
      window.alert(data?.message || "Could not update request");
      setActionLoadingId(0);
      return;
    }

    await loadLogoutRequests();
    setActionLoadingId(0);
  };

  useEffect(() => {
    if (coordinator_id) {
      loadStudents();
      loadLogoutRequests();
    }
  }, [coordinator_id]);

  const filtered = students.filter((s) => {
    const term = search.trim().toLowerCase();
    if (!term) return true;
    return (
      String(s.name || "").toLowerCase().includes(term) ||
      String(s.reg_no || "").toLowerCase().includes(term)
    );
  });

  return (
    <div className="container mt-4">
      <div className="card shadow-sm mb-4">
        <div className="card-body">
          <h5 className="mb-3">Early Logout Requests (Approval Panel)</h5>
          {loadingRequests ? (
            <p className="mb-0">Loading requests...</p>
          ) : logoutRequests.length === 0 ? (
            <p className="text-muted mb-0">No pending requests for today</p>
          ) : (
            <div className="table-responsive">
              <table className="table table-sm table-bordered mb-0">
                <thead className="table-light">
                  <tr>
                    <th>Reg No</th>
                    <th>Name</th>
                    <th>Class</th>
                    <th>Reason</th>
                    <th>Requested At</th>
                    <th>Action</th>
                  </tr>
                </thead>
                <tbody>
                  {logoutRequests.map((request) => (
                    <tr key={request.id}>
                      <td>{request.reg_no || "-"}</td>
                      <td>{request.student_name || "-"}</td>
                      <td>{`${request.dept || "-"} / ${request.year || "-"} / ${request.section || "-"}`}</td>
                      <td>{request.reason || "-"}</td>
                      <td>{request.requested_at || "-"}</td>
                      <td>
                        <div className="d-flex gap-2">
                          <button
                            className="btn btn-success btn-sm"
                            disabled={actionLoadingId === request.id}
                            onClick={() => decideRequest(request.id, "approved")}
                          >
                            Approve
                          </button>
                          <button
                            className="btn btn-outline-danger btn-sm"
                            disabled={actionLoadingId === request.id}
                            onClick={() => decideRequest(request.id, "rejected")}
                          >
                            Reject
                          </button>
                        </div>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          )}
        </div>
      </div>

      <div className="d-flex align-items-center justify-content-between">
        <h3>Assigned Students</h3>
        <input
          className="form-control w-auto"
          placeholder="Search by name or reg no"
          value={search}
          onChange={(e) => setSearch(e.target.value)}
        />
      </div>

      {loading ? (
        <p>Loading students...</p>
      ) : filtered.length === 0 ? (
        <p className="text-muted">No students assigned</p>
      ) : (
        <table className="table table-bordered mt-3">
          <thead className="table-dark">
            <tr>
              <th>Register No</th>
              <th>Name</th>
              <th>Department</th>
              <th>Year</th>
            </tr>
          </thead>
          <tbody>
            {filtered.map((s) => (
              <tr key={s.id}>
                <td>{s.reg_no}</td>
                <td>{s.name}</td>
                <td>{s.dept}</td>
                <td>{s.year}</td>
              </tr>
            ))}
          </tbody>
        </table>
      )}
    </div>
  );
}

import { useEffect, useState } from "react";
import { apiCall, buildUrl } from "../utils/apiClient";

export default function DeanDiscipline() {
  const [actions, setActions] = useState([]);
  const [form, setForm] = useState({ id: "", student_id: "", action_type: "", reason: "", status: "Active" });
  const [error, setError] = useState("");

  const loadActions = async () => {
    const data = await apiCall(buildUrl("dean_endpoints.php?action=get_disciplinary_actions"));
    if (data.status) {
      setActions(data.actions || []);
      setError("");
    } else {
      setError(data.message || "Failed to load actions");
    }
  };

  const submitAction = async (e) => {
    e.preventDefault();
    const action = form.id ? "update_disciplinary_action" : "record_disciplinary_action";
    const data = await apiCall(buildUrl(`dean_endpoints.php?action=${action}`), {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify(form)
    });

    if (!data.status) {
      setError(data.message || "Failed to save action");
      return;
    }

    setForm({ id: "", student_id: "", action_type: "", reason: "", status: "Active" });
    await loadActions();
  };

  const editAction = (row) => {
    setForm({
      id: row.id,
      student_id: row.student_id || "",
      action_type: row.action_type || "",
      reason: row.reason || "",
      status: row.status || "Active"
    });
  };

  const deleteAction = async (id) => {
    const data = await apiCall(buildUrl(`dean_endpoints.php?action=delete_disciplinary_action&id=${id}`));
    if (!data.status) {
      setError(data.message || "Failed to delete action");
      return;
    }
    await loadActions();
  };

  useEffect(() => {
    loadActions();
  }, []);

  return (
    <div>
      <h2 className="mb-4">Disciplinary Actions</h2>
      {error && <div className="alert alert-danger">{error}</div>}

      <div className="card shadow-sm border-0 mb-4">
        <div className="card-header bg-light">
          <h5 className="mb-0">Action Form</h5>
        </div>
        <div className="card-body">
          <form onSubmit={submitAction}>
            <div className="row g-3">
              <div className="col-md-3">
                <label className="form-label">Student ID</label>
                <input
                  className="form-control"
                  value={form.student_id}
                  onChange={(e) => setForm((prev) => ({ ...prev, student_id: e.target.value }))}
                  required={!form.id}
                />
              </div>
              <div className="col-md-3">
                <label className="form-label">Action Type</label>
                <input
                  className="form-control"
                  value={form.action_type}
                  onChange={(e) => setForm((prev) => ({ ...prev, action_type: e.target.value }))}
                  required
                />
              </div>
              <div className="col-md-3">
                <label className="form-label">Status</label>
                <select
                  className="form-select"
                  value={form.status}
                  onChange={(e) => setForm((prev) => ({ ...prev, status: e.target.value }))}
                >
                  <option value="Active">Active</option>
                  <option value="Closed">Closed</option>
                </select>
              </div>
              <div className="col-md-3">
                <label className="form-label">Reason</label>
                <input
                  className="form-control"
                  value={form.reason}
                  onChange={(e) => setForm((prev) => ({ ...prev, reason: e.target.value }))}
                />
              </div>
            </div>
            <div className="mt-3">
              <button className="btn btn-primary" type="submit">
                {form.id ? "Update" : "Add"}
              </button>
              <button
                type="button"
                className="btn btn-outline-secondary ms-2"
                onClick={() => setForm({ id: "", student_id: "", action_type: "", reason: "", status: "Active" })}
              >
                Clear
              </button>
            </div>
          </form>
        </div>
      </div>

      <div className="card shadow-sm border-0">
        <div className="card-header bg-light">
          <h5 className="mb-0">Actions</h5>
        </div>
        <div className="card-body">
          <div className="table-responsive">
            <table className="table table-sm">
              <thead>
                <tr>
                  <th>Student</th>
                  <th>Action</th>
                  <th>Status</th>
                  <th>Reason</th>
                  <th></th>
                </tr>
              </thead>
              <tbody>
                {actions.length ? (
                  actions.map((row) => (
                    <tr key={row.id}>
                      <td>{row.name || row.reg_no || row.student_id}</td>
                      <td>{row.action_type}</td>
                      <td>{row.status}</td>
                      <td>{row.reason || "-"}</td>
                      <td>
                        <button className="btn btn-sm btn-outline-primary me-2" onClick={() => editAction(row)}>
                          Edit
                        </button>
                        <button className="btn btn-sm btn-outline-danger" onClick={() => deleteAction(row.id)}>
                          Delete
                        </button>
                      </td>
                    </tr>
                  ))
                ) : (
                  <tr>
                    <td colSpan="5" className="text-muted">
                      No actions recorded.
                    </td>
                  </tr>
                )}
              </tbody>
            </table>
          </div>
        </div>
      </div>
    </div>
  );
}

