                    <tr key={row.id}>
                      <td>{row.name || row.reg_no || row.student_id}</td>
                      <td>{row.exam_name || row.exam_id}</td>
                      <td>{row.status}</td>
                      <td>{row.updated_marks ?? "-"}</td>
                      <td>
                        <button className="btn btn-sm btn-outline-primary me-2" onClick={() => editRequest(row)}>
