                        <button className="btn btn-sm btn-outline-danger" onClick={() => deleteRequest(row.id)}>
                          Delete
                        </button>
                      </td>
                    </tr>
                  ))
                ) : (
                  <tr>
                    <td colSpan="5" className="text-muted">
                      No requests found.
                    </td>
                  </tr>
                )}
              </tbody>
            </table>
          </div>
        </div>
      </div>
    </div>
  );
}

import { useEffect, useState } from "react";
import { apiCall, buildUrl } from "../utils/apiClient";

export default function ExamSchedules() {
  const [schedules, setSchedules] = useState([]);
  const [form, setForm] = useState({
    id: "",
    exam_name: "",
    subject: "",
    dept: "",
    year: "",
    semester: "",
    exam_date: "",
    exam_time: "",
    duration: ""
  });
  const [error, setError] = useState("");

  const loadSchedules = async () => {
    const data = await apiCall(buildUrl("exam_controller_endpoints.php?action=get_exam_schedules"));
    if (data.status) {
      setSchedules(data.schedules || []);
      setError("");
    } else {
      setError(data.message || "Failed to load schedules");
    }
  };

  const submitSchedule = async (e) => {
    e.preventDefault();
    const action = form.id ? "update_exam_schedule" : "add_exam_schedule";
    const payload = {
      ...form,
      year: form.year ? parseInt(form.year, 10) : 0,
      semester: form.semester ? parseInt(form.semester, 10) : 0,
      duration: form.duration ? parseInt(form.duration, 10) : 0
    };

    const data = await apiCall(buildUrl(`exam_controller_endpoints.php?action=${action}`), {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify(payload)
    });

    if (!data.status) {
      setError(data.message || "Failed to save schedule");
      return;
    }

    setForm({ id: "", exam_name: "", subject: "", dept: "", year: "", semester: "", exam_date: "", exam_time: "", duration: "" });
    await loadSchedules();
  };

  const editSchedule = (row) => {
    setForm({
      id: row.id,
      exam_name: row.exam_name || "",
      subject: row.subject || "",
      dept: row.dept || "",
      year: row.year || "",
      semester: row.semester || "",
      exam_date: row.exam_date || "",
      exam_time: row.exam_time || "",
      duration: row.duration || ""
    });
  };

  const deleteSchedule = async (id) => {
    const data = await apiCall(buildUrl(`exam_controller_endpoints.php?action=delete_exam_schedule&id=${id}`));
    if (!data.status) {
      setError(data.message || "Failed to delete schedule");
      return;
    }
    await loadSchedules();
  };

  useEffect(() => {
    loadSchedules();
  }, []);

  return (
    <div>
      <h2 className="mb-4">Exam Schedules</h2>
      {error && <div className="alert alert-danger">{error}</div>}

      <div className="card shadow-sm border-0 mb-4">
        <div className="card-header bg-light">
          <h5 className="mb-0">Schedule Form</h5>
        </div>
        <div className="card-body">
          <form onSubmit={submitSchedule}>
            <div className="row g-3">
              <div className="col-md-4">
                <label className="form-label">Exam Name</label>
                <input
                  className="form-control"
                  value={form.exam_name}
                  onChange={(e) => setForm((prev) => ({ ...prev, exam_name: e.target.value }))}
                  required
                />
              </div>
              <div className="col-md-4">
                <label className="form-label">Subject</label>
                <input
                  className="form-control"
                  value={form.subject}
                  onChange={(e) => setForm((prev) => ({ ...prev, subject: e.target.value }))}
                  required
                />
              </div>
              <div className="col-md-4">
                <label className="form-label">Department</label>
                <input
                  className="form-control"
                  value={form.dept}
                  onChange={(e) => setForm((prev) => ({ ...prev, dept: e.target.value }))}
                  required
                />
              </div>
              <div className="col-md-2">
                <label className="form-label">Year</label>
                <input
                  className="form-control"
                  value={form.year}
                  onChange={(e) => setForm((prev) => ({ ...prev, year: e.target.value }))}
                />
              </div>
              <div className="col-md-2">
                <label className="form-label">Semester</label>
                <input
                  className="form-control"
                  value={form.semester}
                  onChange={(e) => setForm((prev) => ({ ...prev, semester: e.target.value }))}
                />
              </div>
              <div className="col-md-3">
                <label className="form-label">Exam Date</label>
                <input
                  type="date"
                  className="form-control"
                  value={form.exam_date}
                  onChange={(e) => setForm((prev) => ({ ...prev, exam_date: e.target.value }))}
                  required
                />
              </div>
              <div className="col-md-3">
                <label className="form-label">Exam Time</label>
                <input
                  type="time"
                  className="form-control"
                  value={form.exam_time}
                  onChange={(e) => setForm((prev) => ({ ...prev, exam_time: e.target.value }))}
                />
              </div>
              <div className="col-md-2">
                <label className="form-label">Duration (mins)</label>
                <input
                  className="form-control"
                  value={form.duration}
                  onChange={(e) => setForm((prev) => ({ ...prev, duration: e.target.value }))}
                />
              </div>
            </div>
            <div className="mt-3">
              <button className="btn btn-primary" type="submit">
                {form.id ? "Update" : "Add"}
              </button>
              <button
                type="button"
                className="btn btn-outline-secondary ms-2"
                onClick={() => setForm({ id: "", exam_name: "", subject: "", dept: "", year: "", semester: "", exam_date: "", exam_time: "", duration: "" })}
              >
                Clear
              </button>
            </div>
          </form>
        </div>
      </div>

      <div className="card shadow-sm border-0">
        <div className="card-header bg-light">
          <h5 className="mb-0">Schedules</h5>
        </div>
        <div className="card-body">
          <div className="table-responsive">
            <table className="table table-sm">
              <thead>
                <tr>
                  <th>Exam</th>
                  <th>Subject</th>
                  <th>Dept</th>
                  <th>Date</th>
                  <th>Time</th>
                  <th></th>
                </tr>
              </thead>
              <tbody>
                {schedules.length ? (
                  schedules.map((row) => (
                    <tr key={row.id}>
                      <td>{row.exam_name}</td>
                      <td>{row.subject}</td>
                      <td>{row.dept}</td>
                      <td>{row.exam_date}</td>
                      <td>{row.exam_time || "-"}</td>
                      <td>
                        <button className="btn btn-sm btn-outline-primary me-2" onClick={() => editSchedule(row)}>
                          Edit
                        </button>
                        <button className="btn btn-sm btn-outline-danger" onClick={() => deleteSchedule(row.id)}>
                          Delete
                        </button>
                      </td>
                    </tr>
                  ))
                ) : (
                  <tr>
                    <td colSpan="6" className="text-muted">
                      No schedules found.
                    </td>
                  </tr>
                )}
              </tbody>
            </table>
          </div>
        </div>
      </div>
    </div>
  );
}

import { useEffect, useState } from "react";
import { apiCall, buildUrl } from "../utils/apiClient";

export default function HODAssignCoordinator() {

  // Read auth object from localStorage
  const auth = JSON.parse(localStorage.getItem("user") || "{}");

  const hodTeacherId =
    auth?.user?.linked_id ||
    auth?.linked_id ||
    auth?.user?.teacher_id ||
    auth?.teacher_id ||
    auth?.user?.id ||
    auth?.id ||
    null;

  const [teachers, setTeachers] = useState([]);
  const [selectedTeacher, setSelectedTeacher] = useState(null);
  const [year, setYear] = useState("");
  const [section, setSection] = useState("");
  const [msg, setMsg] = useState("");

  // Load teachers of HOD department
  const loadTeachers = async () => {
    if (!hodTeacherId) {
      setMsg("HOD teacher ID not found. Please login again.");
      return;
    }

    const data = await apiCall(buildUrl("get_hod_teachers.php"), {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ teacher_id: hodTeacherId })
    });

    if (data.status) {
      setTeachers(data.teachers || []);
      setMsg("");
    } else {
      setTeachers([]);
      setMsg(data.message || "No teachers found");
    }
  };

  // Start assigning a teacher
  const startAssign = (teacher) => {
    setSelectedTeacher(teacher);
    setYear("");
    setSection("");
    setMsg("");
  };

  // Confirm assign
  const confirmAssign = async () => {
    if (!year || !section) {
      alert("Enter year and section");
      return;
    }

    const data = await apiCall(buildUrl("assign_coordinator.php"), {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({
        teacher_id: selectedTeacher.id,
        year,
        section,
        assigned_by: hodTeacherId
      })
    });

    if (data.status) {
      setMsg("✅ Coordinator Assigned Successfully");
      setSelectedTeacher(null);
      loadTeachers();
    } else {
      setMsg("❌ " + data.message);
    }
  };

  useEffect(() => {
    loadTeachers();
  }, []);

  return (
    <div className="container mt-4">
      <h3>Assign Class Coordinator</h3>

      {msg && <p className="fw-bold">{msg}</p>}

      {/* Assignment form (only after clicking Assign) */}
      {selectedTeacher && (
        <div className="card p-3 mb-3 border-primary">
          <h5>
            Assign class to <b>{selectedTeacher.name}</b>
          </h5>

          <div className="row mt-2">
            <div className="col-md-6">
              <input
                className="form-control"
                placeholder="Year (e.g. 2)"
                value={year}
                onChange={(e) => setYear(e.target.value)}
              />
            </div>
            <div className="col-md-6">
              <input
                className="form-control"
                placeholder="Section (e.g. A)"
                value={section}
                onChange={(e) => setSection(e.target.value)}
              />
            </div>
          </div>

          <div className="mt-3">
            <button className="btn btn-success me-2" onClick={confirmAssign}>
              Confirm Assign
            </button>
            <button
              className="btn btn-secondary"
              onClick={() => setSelectedTeacher(null)}
            >
              Cancel
            </button>
          </div>
        </div>
      )}

      {/* Teachers list */}
      <table className="table table-bordered">
        <thead className="table-dark">
          <tr>
            <th>Name</th>
            <th>Department</th>
            <th>Status</th>
            <th>Action</th>
          </tr>
        </thead>

        <tbody>
          {teachers.length === 0 && (
            <tr>
              <td colSpan="4" className="text-center text-danger">
                No teachers available
              </td>
            </tr>
          )}

          {teachers.map((t) => (
            <tr key={t.id}>
              <td>{t.name}</td>
              <td>{t.dept}</td>
              <td>
                {Number(t.is_coordinator) === 1 ? (
                  <span className="badge bg-success">
                    Coordinator ({t.assigned_class})
                  </span>
                ) : (
                  <span className="badge bg-secondary">Teacher</span>
                )}
              </td>
              <td>
                {Number(t.is_coordinator) === 0 && (
                  <button
                    className="btn btn-sm btn-primary"
                    onClick={() => startAssign(t)}
                  >
                    Assign
                  </button>
                )}
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}

