import { useEffect, useState } from "react";
import { apiCall, buildUrl } from "../utils/apiClient";

export default function ParentDashboard() {
  const [children, setChildren] = useState([]);
  const [selectedId, setSelectedId] = useState("");
  const [profile, setProfile] = useState(null);
  const [grades, setGrades] = useState([]);
  const [attendance, setAttendance] = useState([]);
  const [error, setError] = useState("");

  const loadChildren = async () => {
    const data = await apiCall(buildUrl("parent_endpoints.php?action=get_my_children"));
    if (data.status) {
      setChildren(data.children || []);
      if (data.children?.length) {
        setSelectedId(String(data.children[0].id));
      }
      setError("");
    } else {
      setError(data.message || "Failed to load children");
    }
  };

  const loadChildData = async (studentId) => {
    if (!studentId) return;
    const [profileData, gradeData, attendanceData] = await Promise.all([
      apiCall(buildUrl(`parent_endpoints.php?action=get_child_profile&student_id=${studentId}`)),
      apiCall(buildUrl(`parent_endpoints.php?action=get_child_grades&student_id=${studentId}`)),
      apiCall(buildUrl(`parent_endpoints.php?action=get_child_attendance&student_id=${studentId}`))
    ]);

    if (profileData.status) setProfile(profileData.student || null);
    if (gradeData.status) setGrades(gradeData.grades || []);
    if (attendanceData.status) setAttendance(attendanceData.attendance || []);

    if (!profileData.status || !gradeData.status || !attendanceData.status) {
      setError(
        profileData.message || gradeData.message || attendanceData.message || "Failed to load student data"
      );
    } else {
      setError("");
    }
  };

  useEffect(() => {
    loadChildren();
  }, []);

  useEffect(() => {
    if (selectedId) {
      loadChildData(selectedId);
    }
  }, [selectedId]);

  return (
    <div>
      <h2 className="mb-4">👨‍👩‍👧 Parent Dashboard</h2>

      {error && <div className="alert alert-danger">{error}</div>}

      <div className="card shadow-sm border-0 mb-4">
        <div className="card-header bg-light">
          <h5 className="mb-0">👶 My Children</h5>
        </div>
        <div className="card-body">
          {children.length ? (
            <div className="d-flex flex-wrap gap-2">
              {children.map((child) => (
                <button
                  key={child.id}
                  className={`btn btn-sm ${String(child.id) === selectedId ? "btn-primary" : "btn-outline-primary"}`}
                  onClick={() => setSelectedId(String(child.id))}
                >
                  {child.name} ({child.reg_no})
                </button>
              ))}
            </div>
          ) : (
            <p className="text-muted">No linked students found.</p>
          )}
        </div>
      </div>

      {profile && (
        <div className="row mb-4">
          <div className="col-lg-4 mb-4">
            <div className="card shadow-sm border-0 h-100">
              <div className="card-header bg-light">
                <h5 className="mb-0">📌 Student Profile</h5>
              </div>
              <div className="card-body">
                <p><strong>Name:</strong> {profile.name}</p>
                <p><strong>Reg No:</strong> {profile.reg_no}</p>
                <p><strong>Dept:</strong> {profile.dept}</p>
                <p><strong>Year:</strong> {profile.year}</p>
                <p><strong>Section:</strong> {profile.section || "-"}</p>
              </div>
            </div>
          </div>

          <div className="col-lg-4 mb-4">
            <div className="card shadow-sm border-0 h-100">
              <div className="card-header bg-light">
                <h5 className="mb-0">🎯 Grades</h5>
              </div>
              <div className="card-body">
                <div className="table-responsive">
                  <table className="table table-sm">
                    <thead>
                      <tr>
                        <th>Semester</th>
                        <th>GPA</th>
                        <th>Result</th>
                      </tr>
                    </thead>
                    <tbody>
                      {grades.length ? (
                        grades.map((row, idx) => (
                          <tr key={`${row.semester}-${idx}`}>
                            <td>{row.semester}</td>
                            <td>{row.gpa}</td>
                            <td>{row.result}</td>
                          </tr>
                        ))
                      ) : (
                        <tr>
                          <td colSpan="3" className="text-muted">No grades available.</td>
                        </tr>
                      )}
                    </tbody>
                  </table>
                </div>
              </div>
            </div>
          </div>

          <div className="col-lg-4 mb-4">
            <div className="card shadow-sm border-0 h-100">
              <div className="card-header bg-light">
                <h5 className="mb-0">📅 Attendance</h5>
              </div>
              <div className="card-body">
                <div className="table-responsive">
                  <table className="table table-sm">
                    <thead>
                      <tr>
                        <th>Date</th>
                        <th>Status</th>
                      </tr>
                    </thead>
                    <tbody>
                      {attendance.length ? (
                        attendance.map((row, idx) => (
                          <tr key={`${row.date}-${idx}`}>
                            <td>{row.date}</td>
                            <td>{row.status}</td>
                          </tr>
                        ))
                      ) : (
                        <tr>
                          <td colSpan="2" className="text-muted">No attendance records.</td>
                        </tr>
                      )}
                    </tbody>
                  </table>
                </div>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

import { useEffect, useState } from "react";
import { apiCall, buildUrl } from "../utils/apiClient";

export default function ParentFeedback() {
  const [feedback, setFeedback] = useState([]);
  const [form, setForm] = useState({ student_id: "", feedback_type: "", message: "" });
  const [error, setError] = useState("");

  const loadFeedback = async () => {
    const data = await apiCall(buildUrl("parent_endpoints.php?action=get_feedback"));
    if (data.status) {
      setFeedback(data.feedback || []);
      setError("");
    } else {
      setError(data.message || "Failed to load feedback");
    }
  };

  const submitFeedback = async (e) => {
    e.preventDefault();
    const data = await apiCall(buildUrl("parent_endpoints.php?action=add_feedback"), {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify(form)
    });

    if (!data.status) {
      setError(data.message || "Failed to submit feedback");
      return;
    }

    setForm({ student_id: "", feedback_type: "", message: "" });
    await loadFeedback();
  };

  const deleteFeedback = async (id) => {
    const data = await apiCall(buildUrl(`parent_endpoints.php?action=delete_feedback&id=${id}`));
    if (!data.status) {
      setError(data.message || "Failed to delete feedback");
      return;
    }
    await loadFeedback();
  };

  useEffect(() => {
    loadFeedback();
  }, []);

  return (
    <div>
      <h2 className="mb-4">Parent Feedback</h2>
      {error && <div className="alert alert-danger">{error}</div>}

      <div className="card shadow-sm border-0 mb-4">
        <div className="card-header bg-light">
          <h5 className="mb-0">Submit Feedback</h5>
        </div>
        <div className="card-body">
          <form onSubmit={submitFeedback}>
            <div className="row g-3">
              <div className="col-md-3">
                <label className="form-label">Student ID</label>
                <input
                  className="form-control"
                  value={form.student_id}
                  onChange={(e) => setForm((prev) => ({ ...prev, student_id: e.target.value }))}
                  required
                />
              </div>
              <div className="col-md-3">
                <label className="form-label">Type</label>
                <input
                  className="form-control"
                  value={form.feedback_type}
                  onChange={(e) => setForm((prev) => ({ ...prev, feedback_type: e.target.value }))}
                />
              </div>
              <div className="col-md-6">
                <label className="form-label">Message</label>
                <input
                  className="form-control"
                  value={form.message}
                  onChange={(e) => setForm((prev) => ({ ...prev, message: e.target.value }))}
                  required
                />
              </div>
            </div>
            <div className="mt-3">
              <button className="btn btn-primary" type="submit">
                Submit
              </button>
            </div>
          </form>
        </div>
      </div>

      <div className="card shadow-sm border-0">
        <div className="card-header bg-light">
          <h5 className="mb-0">Feedback History</h5>
        </div>
        <div className="card-body">
          <div className="table-responsive">
            <table className="table table-sm">
              <thead>
                <tr>
                  <th>Student</th>
                  <th>Type</th>
                  <th>Status</th>
                  <th>Message</th>
                  <th></th>
                </tr>
              </thead>
              <tbody>
                {feedback.length ? (
                  feedback.map((row) => (
                    <tr key={row.id}>
                      <td>{row.name || row.reg_no || row.student_id}</td>
                      <td>{row.feedback_type || "-"}</td>
                      <td>{row.status}</td>
                      <td>{row.message}</td>
                      <td>
                        <button className="btn btn-sm btn-outline-danger" onClick={() => deleteFeedback(row.id)}>
                          Delete
                        </button>
                      </td>
                    </tr>
                  ))
                ) : (
                  <tr>
                    <td colSpan="5" className="text-muted">
                      No feedback submitted.
                    </td>
                  </tr>
                )}
              </tbody>
            </table>
          </div>
        </div>
      </div>
    </div>
  );
}

