import { useEffect, useState } from "react";
import { apiCall, buildUrl } from "../utils/apiClient";

export default function StudentDashboard() {

  const user = JSON.parse(localStorage.getItem("user"));
  const student_id =
    user?.student_id ||
    user?.linked_id ||
    user?.user?.student_id ||
    user?.user?.linked_id ||
    user?.user?.user_id ||
    user?.user?.id ||
    user?.user_id ||
    user?.id;

  const [campusStatus, setCampusStatus] = useState("-");
  const [lastUpdate, setLastUpdate] = useState("");
  const [summary, setSummary] = useState({
    attendance: 0,
    feesPending: 0,
    totalClasses: 0
  });
  const [attendanceRows, setAttendanceRows] = useState([]);
  const [logoutRequest, setLogoutRequest] = useState(null);
  const [error, setError] = useState("");

  useEffect(() => {

    if (!student_id) {
      setError("Student ID not found. Please log in again.");
      return;
    }

    // ❌ BROWSER CHECK
    if (!navigator.geolocation) {
      console.error("❌ Geolocation not supported");
      return;
    }

    console.log("✅ Live location tracking started");

    // ✅ SEND LOCATION TO BACKEND
    const sendLocation = async (lat, lng) => {
      try {
        const data = await apiCall(buildUrl("update_location.php"), {
          method: "POST",
          headers: {
            "Content-Type": "application/json"
          },
          body: JSON.stringify({
            student_id: student_id,
            latitude: lat,
            longitude: lng
          })
        });

        if (data.status) {
          setCampusStatus(data.campus_status || "-");
          setLastUpdate(new Date().toLocaleTimeString());
        }

      } catch (err) {
        console.error("❌ Location send failed", err);
      }
    };

    // ✅ WATCH GPS POSITION
    const watchId = navigator.geolocation.watchPosition(

      // SUCCESS
      (position) => {
        const { latitude, longitude } = position.coords;
        console.log("📡 GPS OK:", latitude, longitude);
        sendLocation(latitude, longitude);
      },

      // ERROR
      (error) => {
        console.error("❌ GPS Error:", error.message);
      },

      // OPTIONS
      {
        enableHighAccuracy: true,
        timeout: 20000,
        maximumAge: 0
      }
    );

    // CLEANUP
    return () => navigator.geolocation.clearWatch(watchId);

  }, [student_id]);

  useEffect(() => {
    const loadSummary = async () => {
      if (!student_id) return;

      try {
        const history = await apiCall(
          buildUrl(`get_student_history.php?student_id=${student_id}`)
        );
        const fees = await apiCall(
          buildUrl(`get_student_fees.php?student_id=${student_id}`)
        );
        const request = await apiCall(buildUrl("get_logout_requests.php"));

        setSummary({
          attendance: history?.percentage || 0,
          totalClasses: history?.total || 0,
          feesPending: fees?.summary?.pending || 0
        });
        setAttendanceRows(history?.history || []);

        if (request?.status) {
          setLogoutRequest(request.request || null);
        }
      } catch (err) {
        console.error("Error loading student summary:", err);
        // Don't block dashboard if summary fails to load
      }
    };

    loadSummary();
  }, [student_id]);

  // ✅ SIMPLE, CLEAN UI (NO CONFUSION)
  if (error) {
    return <div className="container mt-4 text-danger">{error}</div>;
  }

  return (
    <div className="container-fluid px-2 px-md-4 py-3">
      <div className="card p-3 p-md-4 shadow-sm mb-4">
        <h3 className="mb-2">Student Dashboard</h3>
        <p className="text-success mb-2">
          Live Location Tracking Enabled ✔
        </p>
        <p className="text-muted mb-0">
          Campus status: <b>{campusStatus}</b> {lastUpdate && `(Last update ${lastUpdate})`}
        </p>
      </div>

      {logoutRequest && (
        <div className={`alert ${logoutRequest.status === "approved" ? "alert-success" : logoutRequest.status === "rejected" ? "alert-danger" : "alert-warning"} mb-4`}>
          <b>Early Logout Request:</b> {logoutRequest.status?.toUpperCase()}
          {logoutRequest.reason ? ` | Reason: ${logoutRequest.reason}` : ""}
          {logoutRequest.decision_note ? ` | Note: ${logoutRequest.decision_note}` : ""}
        </div>
      )}

      <div className="grid-3 mb-4">
        <div className="card p-3 shadow-sm text-center">
          <h6 className="text-muted mb-2">Attendance %</h6>
          <h2 className="text-primary">{summary.attendance}%</h2>
        </div>
        <div className="card p-3 shadow-sm text-center">
          <h6 className="text-muted mb-2">Total Classes</h6>
          <h2 className="text-success">{summary.totalClasses}</h2>
        </div>
        <div className="card p-3 shadow-sm text-center">
          <h6 className="text-muted mb-2">Fees Pending</h6>
          <h2 className="text-danger">₹{summary.feesPending}</h2>
        </div>
      </div>

      <div className="card p-3 p-md-4 shadow-sm">
        <h5 className="mb-3">Subject-wise Attendance</h5>

        <div className="table-responsive">
          <table className="table table-bordered table-striped mb-0">
            <thead>
              <tr>
                <th>Subject</th>
                <th>Status</th>
                <th>Date</th>
                <th>Time</th>
              </tr>
            </thead>
            <tbody>
              {attendanceRows.map((row, index) => {
                const startedAt = row?.started_at || "";
                const [fallbackDate, fallbackTime = ""] = startedAt.split(" ");
                const status = row?.status || "-";

                return (
                  <tr key={`${row?.subject || "subject"}-${startedAt}-${index}`}>
                    <td>{row?.subject || "-"}</td>
                    <td
                      className={
                        status === "Present"
                          ? "text-success fw-semibold"
                          : status === "OD"
                            ? "text-primary fw-semibold"
                            : "text-danger fw-semibold"
                      }
                    >
                      {status}
                    </td>
                    <td>{row?.attendance_date || fallbackDate || "-"}</td>
                    <td>{row?.attendance_time || fallbackTime || "-"}</td>
                  </tr>
                );
              })}

              {attendanceRows.length === 0 && (
                <tr>
                  <td colSpan="4" className="text-center text-muted">
                    No attendance records found.
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
}

import { useEffect, useState } from "react";
import { apiCall, buildUrl } from "../utils/apiClient";

export default function StudentFees(){

  const user = JSON.parse(localStorage.getItem("user"));
  const student_id =
    user?.student_id ||
    user?.linked_id ||
    user?.user?.student_id ||
    user?.user?.linked_id ||
    user?.user?.user_id ||
    user?.user?.id ||
    user?.user_id ||
    user?.id;

  const [summary,setSummary] = useState({
    total:0,
    paid:0,
    pending:0
  });

  const [fees,setFees] = useState([]);
  const [payments,setPayments] = useState([]);
  const [loading,setLoading] = useState(true);

  const loadFees = async ()=>{
    try{
      if (!student_id) {
        setLoading(false);
        return;
      }
      const data = await apiCall(
        buildUrl(`get_student_fees.php?student_id=${student_id}`)
      );

      if(data.status){
        setSummary(data.summary || { total: 0, paid: 0, pending: 0 });
        setFees(data.fees || []);
        setPayments(data.payments || []);
      }

    }catch(e){
      console.log("FEES ERROR:",e);
    }

    setLoading(false);
  };

  useEffect(()=>{ loadFees(); },[]);

  return(
    <div className="container mt-4">

      <div className="card p-4 shadow">

        <h3>Fees & Payments</h3>
        <p className="text-secondary">View your outstanding & paid fee details</p>

        <hr/>

        {loading && <h5>Loading...</h5>}

        {!loading && (
          <>
            {/* SUMMARY CARDS */}
            <div className="row text-center mb-4">

              <div className="col-md-4">
                <div className="card p-3 shadow">
                  <h6>Total Fees</h6>
                  <h2>₹{summary.total}</h2>
                </div>
              </div>

              <div className="col-md-4">
                <div className="card p-3 shadow text-success">
                  <h6>Paid</h6>
                  <h2>₹{summary.paid}</h2>
                </div>
              </div>

              <div className="col-md-4">
                <div className="card p-3 shadow text-danger">
                  <h6>Pending</h6>
                  <h2>₹{summary.pending}</h2>
                </div>
              </div>

            </div>

            {/* FEES TABLE */}
            <table className="table table-bordered">
              <thead style={{background:"#0d6efd", color:"white"}}>
                <tr>
                  <th>Total Amount</th>
                  <th>Paid</th>
                  <th>Balance</th>
                  <th>Due Date</th>
                  <th>Status</th>
                </tr>
              </thead>

              <tbody>

                {fees.map((f,i)=>(
                  <tr key={i}>
                    <td>₹{f.total_amount}</td>
                    <td>₹{f.paid_amount || 0}</td>
                    <td>₹{f.balance}</td>
                    <td>{f.due_date || "-"}</td>
                    <td className={f.status === "PAID" || f.status === "Paid" ? "text-success" : "text-danger"}>
                      <b>{f.status || "PENDING"}</b>
                    </td>
                  </tr>
                ))}

                {fees.length===0 && (
                  <tr>
                    <td colSpan="6" className="text-center">
                      No Fee Records Found
                    </td>
                  </tr>
                )}

              </tbody>
            </table>

            <hr/>

            {/* PAYMENTS */}
            <h5>Payment History</h5>
            <table className="table table-bordered">
              <thead className="table-light">
                <tr>
                  <th>Amount</th>
                  <th>Method</th>
                  <th>Transaction</th>
                  <th>Paid On</th>
                </tr>
              </thead>
              <tbody>
                {payments.map((p) => (
                  <tr key={p.id}>
                    <td>₹{p.amount}</td>
                    <td>{p.method || "-"}</td>
                    <td>{p.transaction_id || "-"}</td>
                    <td>{p.paid_on ? new Date(p.paid_on).toLocaleString() : "-"}</td>
                  </tr>
                ))}
                {payments.length === 0 && (
                  <tr>
                    <td colSpan="4" className="text-center">
                      No payments recorded
                    </td>
                  </tr>
                )}
              </tbody>
            </table>

          </>
        )}

      </div>

    </div>
  );
}

import { useEffect, useState } from "react";
import { apiCall, buildUrl } from "../utils/apiClient";

export default function StudentGrades(){

  const user = JSON.parse(localStorage.getItem("user"));
  const student_id =
    user?.student_id ||
    user?.linked_id ||
    user?.user?.student_id ||
    user?.user?.linked_id ||
    user?.user?.user_id ||
    user?.user?.id ||
    user?.user_id ||
    user?.id;

  const [grades,setGrades] = useState([]);
  const [summary,setSummary] = useState({
    cgpa:0,
    semesters:0,
    arrears:0
  });
  const [loading,setLoading] = useState(true);

  const loadGrades = async ()=>{
    try{
      if (!student_id) {
        setLoading(false);
        return;
      }
      const data = await apiCall(
        buildUrl(`get_student_grades.php?student_id=${student_id}`)
      );

      if(data.status){
        setGrades(data.grades || []);
        setSummary(data.summary || { cgpa: 0, semesters: 0, arrears: 0 });
      }

    }catch(e){
      console.log(e);
    }

    setLoading(false);
  };

  useEffect(()=>{ loadGrades(); },[]);

  return(
    <div className="container mt-4">

      <div className="card p-4 shadow">

        <h3>Grade Details</h3>
        <p className="text-secondary">
          View your semester-wise grades and earned credits
        </p>

        <hr/>

        {loading && <h5>Loading...</h5>}

        {!loading && (
          <>
            {/* SUMMARY */}
            <div className="row text-center mb-4">

              <div className="col-md-4">
                <div className="card p-3 shadow">
                  <h6>CGPA</h6>
                  <h2>{summary.cgpa}</h2>
                </div>
              </div>

              <div className="col-md-4">
                <div className="card p-3 shadow text-success">
                  <h6>Semesters</h6>
                  <h2>{summary.semesters}</h2>
                </div>
              </div>

              <div className="col-md-4">
                <div className="card p-3 shadow text-danger">
                  <h6>No of Arrears</h6>
                  <h2>{summary.arrears}</h2>
                </div>
              </div>

            </div>

            {/* GRADES TABLE */}
            <table className="table table-bordered">
              <thead style={{background:"#0d6efd", color:"white"}}>
                <tr>
                  <th>Semester</th>
                  <th>GPA</th>
                  <th>Result</th>
                  <th>Recorded On</th>
                </tr>
              </thead>

              <tbody>

                {grades.map((g,i)=>(
                  <tr key={i}>
                    <td>{g.semester}</td>
                    <td><b>{g.gpa}</b></td>
                    <td>{g.result || "-"}</td>
                    <td>{g.created_at ? new Date(g.created_at).toLocaleDateString() : "-"}</td>
                  </tr>
                ))}

                {grades.length===0 && (
                  <tr>
                    <td colSpan="4" className="text-center">
                      No Grade Records Found
                    </td>
                  </tr>
                )}

              </tbody>
            </table>

          </>
        )}

      </div>

    </div>
  );
}

import { useEffect, useState } from "react";
import { apiCall, buildUrl } from "../utils/apiClient";

export default function StudentHistory(){

  const user = JSON.parse(localStorage.getItem("user"));
  const student_id =
    user?.student_id ||
    user?.linked_id ||
    user?.user?.student_id ||
    user?.user?.linked_id ||
    user?.user?.user_id ||
    user?.user?.id ||
    user?.user_id ||
    user?.id;

  const [summary,setSummary] = useState({
    total:0,
    present:0,
    absent:0,
    percentage:0
  });

  const [history,setHistory] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");

  const [subject,setSubject] = useState("");
  const [from,setFrom] = useState("");
  const [to,setTo] = useState("");

  const loadHistory = async ()=>{

    if (!student_id) {
      setError("Student ID not found. Please log in again.");
      return;
    }

    setLoading(true);
    setError("");

    const params = new URLSearchParams({ student_id });
    if (subject) params.append("subject", subject);
    if (from) params.append("from", from);
    if (to) params.append("to", to);

    const data = await apiCall(buildUrl(`get_student_history.php?${params.toString()}`));

    if(data.status){
      setSummary(data);
      setHistory(data.history || []);
    } else {
      setError(data.message || "Failed to load history");
    }

    setLoading(false);
  };

  useEffect(()=>{ loadHistory(); },[]);

  return(
    <div className="container mt-4">

      <div className="card p-4 shadow">

        <h3>Attendance History</h3>

        {/* FILTERS */}
        <div className="row mt-3">

          <div className="col-md-3">
            <input 
              placeholder="Subject"
              className="form-control"
              value={subject}
              onChange={e=>setSubject(e.target.value)}
            />
          </div>

          <div className="col-md-3">
            <input 
              type="date"
              className="form-control"
              value={from}
              onChange={e=>setFrom(e.target.value)}
            />
          </div>

          <div className="col-md-3">
            <input 
              type="date"
              className="form-control"
              value={to}
              onChange={e=>setTo(e.target.value)}
            />
          </div>

          <div className="col-md-3">
            <button className="btn btn-primary w-100"
              onClick={loadHistory}>
              Apply Filters
            </button>
          </div>

        </div>

        <hr/>

        {error && (
          <div className="alert alert-danger text-center fw-bold">
            {error}
          </div>
        )}

        {loading && (
          <div className="alert alert-info text-center">Loading...</div>
        )}

        {/* WARNING BANNERS */}
        {summary.total > 0 && summary.percentage < 75 && (
          <div className="alert alert-danger text-center fw-bold">
            ⚠ LOW ATTENDANCE WARNING — Your attendance is {summary.percentage}%.
            Minimum 75% attendance is required!
          </div>
        )}

        {summary.percentage >= 75 && summary.percentage < 80 && (
          <div className="alert alert-warning text-center fw-bold">
            🟡 CAUTION — Attendance is {summary.percentage}%. Maintain consistency!
          </div>
        )}

        {summary.percentage >= 80 && summary.total > 0 && (
          <div className="alert alert-success text-center fw-bold">
            ✅ Good! Your attendance is {summary.percentage}%.
          </div>
        )}

        {/* SUMMARY */}
        <div className="row text-center mb-3">

          <div className="col-md-3">
            <div className="card p-3 shadow">
              <h6>Total Classes</h6>
              <h2>{summary.total}</h2>
            </div>
          </div>

          <div className="col-md-3">
            <div className="card p-3 shadow text-success">
              <h6>Present</h6>
              <h2>{summary.present}</h2>
            </div>
          </div>

          <div className="col-md-3">
            <div className="card p-3 shadow text-danger">
              <h6>Absent</h6>
              <h2>{summary.absent}</h2>
            </div>
          </div>

          <div className="col-md-3">
            <div className="card p-3 shadow text-primary">
              <h6>Percentage</h6>
              <h2>{summary.percentage}%</h2>
            </div>
          </div>

        </div>

        {/* HISTORY TABLE */}
        <table className="table table-bordered">
          <thead>
            <tr>
              <th>Subject</th>
              <th>Date</th>
              <th>Status</th>
            </tr>
          </thead>

          <tbody>
            {history.map((h,i)=>(
              <tr key={i}>
                <td>{h.subject}</td>
                <td>{h.started_at}</td>
                <td className={h.status === "Present" ? "text-success" : "text-danger"}>
                  {h.status}
                </td>
              </tr>
            ))}

            {history.length === 0 && 
              <tr>
                <td colSpan="3" className="text-center">No Data Found</td>
              </tr>
            }
          </tbody>
        </table>

      </div>

    </div>
  );
}

import { useEffect, useState } from "react";
import { apiCall, buildUrl } from "../utils/apiClient";

export default function StudentList(){

  const [students,setStudents] = useState([]);
  const [search,setSearch] = useState("");
  const [dept,setDept] = useState("");
  const [departments,setDepartments] = useState([]);
  const [year,setYear] = useState("");
  const [page,setPage] = useState(1);
  const [total,setTotal] = useState(0);

  const load = async ()=>{
    const qs = new URLSearchParams({ search: search || '', dept: dept || '', year: year || '', page: page || 1 }).toString();
    const data = await apiCall(buildUrl(`get_students_advanced.php?${qs}`));
    if(data.status){
      setStudents(data.students || []);
      setTotal(data.total || 0);
    } else {
      setStudents([]);
      setTotal(0);
    }
  };

  useEffect(()=>{ load(); },[page,dept,year]);

  useEffect(()=>{
    const loadDepts = async ()=>{
      try{
        const data = await apiCall(buildUrl('get_departments.php'));
        if(data.status && Array.isArray(data.departments)) setDepartments(data.departments);
      }catch{
        // ignore - we'll fall back to hardcoded list
      }
    };
    loadDepts();
  },[]);

  const totalPages = Math.ceil(total / 10);

  const handleExport = async () => {
    try {
      const res = await fetch(buildUrl("export_students_csv.php"));
      if (!res.ok) {
        throw new Error("Export failed");
      }

      const blob = await res.blob();
      const url = window.URL.createObjectURL(blob);
      const link = document.createElement("a");
      link.href = url;
      link.download = "students.csv";
      document.body.appendChild(link);
      link.click();
      link.remove();
      window.URL.revokeObjectURL(url);
    } catch {
      alert("Failed to export students. Please try again.");
    }
  };

  return(
    <div className="container mt-4">

      {/* Title + Export Button */}
      <div className="d-flex justify-content-between align-items-center">
        <h3>Students List</h3>

        <button type="button" onClick={handleExport} className="btn btn-success">
          Export to CSV
        </button>

      </div>

      <div className="card p-3 shadow mt-3">

        {/* Filters Row */}
        <div className="row mb-3">

          <div className="col-md-4">
            <input 
              className="form-control"
              placeholder="Search Reg No / Name"
              value={search}
              onChange={(e)=>setSearch(e.target.value)}
              onKeyDown={(e)=> e.key === "Enter" && load()}
            />
          </div>

          <div className="col-md-3">
            <select className="form-select" value={dept} onChange={(e)=>setDept(e.target.value)}>
              <option value="">All Departments</option>
              {(departments.length ? departments : ["CSE","BSC(IT&CS)","IT","ECE","EEE","MECH"]).map(d=>{
                // support backend returning objects like {id,dept_name} or simple strings
                const name = (typeof d === 'string') ? d : (d.dept_name || d.name || '');
                const key = (typeof d === 'string') ? name : (d.id || name);
                return <option key={key} value={name}>{name}</option>
              })}
            </select>
          </div>

          <div className="col-md-2">
            <select className="form-select" onChange={(e)=>setYear(e.target.value)}>
              <option value="">Year</option>
              <option value="1">1st Year</option>
              <option value="2">2nd Year</option>
              <option value="3">3rd Year</option>
              <option value="4">4th Year</option>
            </select>
          </div>

          <div className="col-md-2">
            <button className="btn btn-primary w-100" onClick={()=>{setPage(1); load();}}>
              Search
            </button>
          </div>

        </div>

        {/* Table */}
        <table className="table table-bordered table-striped">
          <thead>
            <tr>
              <th>Reg No</th>
              <th>Name</th>
              <th>Dept</th>
              <th>Year</th>
              <th>Admission Year</th>
              <th>Action</th>
            </tr>
          </thead>

          <tbody>
            {students.map(s=>(
              <tr key={s.id}>
                <td>{s.reg_no}</td>
                <td>{s.name}</td>
                <td>{s.dept}</td>
                <td>{s.year}</td>
                <td>{s.admission_year}</td>

                <td>

                  <a className="btn btn-primary btn-sm me-2" href={`/admin/student/${s.id}`}>
                    View
                  </a>

                  <a className="btn btn-warning btn-sm me-2" href={`/admin/student/edit/${s.id}`}>
                    Edit
                  </a>

                  <button 
                    className="btn btn-danger btn-sm"
                    onClick={async ()=>{
                      if(window.confirm("Delete this student?")){
                        let res = await fetch(`http://localhost/SmartCampus/backend/delete_student.php?id=${s.id}`);
                        let data = await res.json();
                        alert(data.message);
                        window.location.reload();
                      }
                    }}
                  >
                    Delete
                  </button>

                </td>
              </tr>
            ))}

            {students.length === 0 && (
              <tr>
                <td colSpan="6" className="text-center">
                  No Records Found
                </td>
              </tr>
            )}

          </tbody>
        </table>

        {/* Pagination */}
        <div className="d-flex justify-content-between">

          <button 
            className="btn btn-secondary"
            disabled={page===1}
            onClick={()=>setPage(page-1)}
          >
            Prev
          </button>

          <span className="mt-2">
            Page {page} / {totalPages || 1}
          </span>

          <button 
            className="btn btn-secondary"
            disabled={page===totalPages}
            onClick={()=>setPage(page+1)}
          >
            Next
          </button>

        </div>

      </div>
    </div>
  );
}

import React, { useEffect, useState } from "react";
import { apiCall, buildUrl } from "../utils/apiClient";

export default function StudentMarks(){

  const user = JSON.parse(localStorage.getItem("user"));
  const student_id =
    user?.student_id ||
    user?.linked_id ||
    user?.user?.student_id ||
    user?.user?.linked_id ||
    user?.user?.user_id ||
    user?.user?.id ||
    user?.user_id ||
    user?.id;
  const [marks,setMarks] = useState([]);
  const [loading,setLoading] = useState(true);
  const [expanded,setExpanded] = useState(null);

  const loadMarks = async () => {
    if (!student_id) {
      setLoading(false);
      return;
    }
    const data = await apiCall(
      buildUrl(`get_student_marks.php?student_id=${student_id}`)
    );
    if (data.status) {
      setMarks(data.marks || []);
    }
    setLoading(false);
  };


  useEffect(()=>{ loadMarks(); },[]);

  return(
    <div className="container mt-4">
      
      <div className="card p-4 shadow">

        <h3>Marks Details</h3>
        <p className="text-secondary">
          Internal & Assessment marks for each registered course
        </p>

        <hr/>

        {loading && <h5>Loading...</h5>}

        {!loading && (
          <table className="table table-bordered table-striped">
            <thead style={{background:"#0d6efd",color:"white"}}>
              <tr>
                <th>#</th>
                <th>Subject</th>
                <th>Semester</th>
                <th>Total Marks</th>
                <th>View</th>
              </tr>
            </thead>

            <tbody>

              {marks.map((c,i)=>(
                <React.Fragment key={c.id || `${c.subject}-${c.semester}-${i}`}>
                  {/* MAIN ROW */}
                  <tr>
                    <td>{i+1}</td>
                    <td><b>{c.subject || "N/A"}</b></td>
                    <td>{c.semester}</td>
                    <td><b>{c.total || "-"}</b></td>

                    <td>
                      <button 
                        className="btn btn-primary btn-sm"
                        onClick={()=> setExpanded(expanded === i ? null : i)}
                      >
                        {expanded === i ? "Hide" : "View"}
                      </button>
                    </td>
                  </tr>

                  {/* EXPANDED MARK TABLE */}
                  {expanded === i && (
                    <tr>
                      <td colSpan="5">
                        <table className="table table-bordered mb-0">
                          <thead className="table-light">
                            <tr>
                              <th>S.No</th>
                              <th>Assessment</th>
                              <th>Marks</th>
                            </tr>
                          </thead>

                          <tbody>
                            <tr>
                              <td>1</td>
                              <td>CIA 1</td>
                              <td><b>{c.cia1 || 0}</b></td>
                            </tr>
                            <tr>
                              <td>2</td>
                              <td>CIA 2</td>
                              <td><b>{c.cia2 || 0}</b></td>
                            </tr>
                            <tr>
                              <td>3</td>
                              <td>CIA 3</td>
                              <td><b>{c.cia3 || 0}</b></td>
                            </tr>
                            <tr>
                              <td>4</td>
                              <td>Attendance Mark</td>
                              <td><b>{c.attendance_mark || 0}</b></td>
                            </tr>
                          </tbody>
                        </table>
                      </td>
                    </tr>
                  )}

                </React.Fragment>
              ))}

              {marks.length === 0 && (
                <tr>
                  <td colSpan="5" className="text-center">
                    No Marks Found
                  </td>
                </tr>
              )}

            </tbody>
          </table>
        )}

      </div>
    </div>
  );
}

import { useEffect, useState } from "react";
import { useParams } from "react-router-dom";

export default function StudentProfile(){

  const { id } = useParams();
  const [s,setS] = useState(null);
  const [error, setError] = useState(null);

  const load = async ()=>{
    try{
      setError(null);
      let res = await fetch(`http://localhost/SmartCampus/backend/get_student_profile.php?id=${id}`);
      if(!res.ok) throw new Error(`HTTP ${res.status}`);
      let data = await res.json();
      if(data.status) setS(data.student);
      else setError(data.message || 'Failed to load student');
    }catch(err){
      console.error('Failed to load student profile', err);
      setError(err.message || 'Network error');
    }
  }

  useEffect(()=>{ if(id) load(); },[id]);

  if(error) return <h3 className="m-5 text-danger">Error: {error}</h3>;
  if(!s) return <h3 className="m-5">Loading...</h3>;

  return(
    <div className="container mt-4">

      <div className="card p-4 shadow">

        {/* Student Photo */}
        <div style={{textAlign:"center"}}>
          <img 
            src={
              s.photo 
              ? `http://localhost/SmartCampus/backend/uploads/students/${s.photo}` 
              : "https://cdn-icons-png.flaticon.com/512/149/149071.png"
            }
            alt="student"
            style={{
              width:"140px",
              height:"140px",
              borderRadius:"50%",
              objectFit:"cover",
              border:"3px solid #0d6efd",
              marginBottom:"10px"
            }}
          />
        </div>

        {/* Upload Input */}
        <input 
          type="file"
          className="form-control mb-3"
          onChange={async (e)=>{

            const formData = new FormData();
            formData.append("id", id);
            formData.append("photo", e.target.files[0]);

            let res = await fetch(
              "http://localhost/SmartCampus/backend/upload_student_photo.php",
              {
                method:"POST",
                body: formData
              }
            );

            let data = await res.json();
            alert(data.message);
            window.location.reload();
          }}
        />

        <h3>{s.name}</h3>
        <p><b>Reg No:</b> {s.reg_no}</p>
        <p><b>Department:</b> {s.dept}</p>
        <p><b>Year:</b> {s.year}</p>
        <p><b>Semester:</b> {s.semester}</p>

        <hr/>

        <h5>Personal Details</h5>
        <p><b>Gender:</b> {s.gender}</p>
        <p><b>DOB:</b> {s.dob}</p>
        <p><b>Blood Group:</b> {s.blood_group}</p>

        <hr/>

        <h5>Contact</h5>
        <p><b>Phone:</b> {s.student_phone}</p>
        <p><b>Email:</b> {s.student_email}</p>
        <p><b>Address:</b> {s.address}, {s.city}, {s.state} - {s.pincode}</p>

        <hr/>

        <h5>Parent</h5>
        <p><b>Father:</b> {s.father_name}</p>
        <p><b>Mother:</b> {s.mother_name}</p>
        <p><b>Parent Phone:</b> {s.parent_phone}</p>

      </div>

    </div>
  );
}

