import { useEffect, useMemo, useState } from "react";
import { apiCall, buildUrl } from "../utils/apiClient";

export default function SubjectControllerTools() {
  const stored = JSON.parse(localStorage.getItem("user") || "{}");
  const teacherId =
    stored?.teacher_id ||
    stored?.linked_id ||
    stored?.user?.linked_id ||
    stored?.user?.teacher_id ||
    stored?.user?.user_id ||
    stored?.user?.id ||
    stored?.user_id ||
    stored?.id;

  const [dept, setDept] = useState("");
  const [loading, setLoading] = useState(true);
  const [isController, setIsController] = useState(false);
  const [subjects, setSubjects] = useState([]);
  const [classes, setClasses] = useState([]);
  const [teachers, setTeachers] = useState([]);
  const [plans, setPlans] = useState([]);
  const [assignments, setAssignments] = useState([]);
  const [timetable, setTimetable] = useState([]);
  const [notice, setNotice] = useState("");

  const [newSubject, setNewSubject] = useState({
    year: "",
    semester: "",
    subject_code: "",
    subject_name: "",
    credits: ""
  });

  const [planForm, setPlanForm] = useState({
    classKey: "",
    subjectId: ""
  });

  const [assignForm, setAssignForm] = useState({
    planId: "",
    teacherId: ""
  });

  const [timetableForm, setTimetableForm] = useState({
    classKey: "",
    day: "Monday",
    period: "1",
    planId: "",
    teacherId: ""
  });

  const dayOptions = ["Monday", "Tuesday", "Wednesday", "Thursday", "Friday", "Saturday"];

  const classOptions = useMemo(() => {
    return classes.map((c) => ({
      key: `${c.year}|${c.section}`,
      label: `Year ${c.year} - ${c.section}`,
      year: c.year,
      section: c.section
    }));
  }, [classes]);

  const approvedPlans = useMemo(
    () => plans.filter((plan) => plan.status === "approved"),
    [plans]
  );

  const approvedAssignments = useMemo(
    () => assignments.filter((assignment) => assignment.status === "approved"),
    [assignments]
  );

  const timetableAssignments = useMemo(() => {
    if (!timetableForm.planId) return [];
    return approvedAssignments.filter(
      (assignment) => String(assignment.plan_id) === String(timetableForm.planId)
    );
  }, [approvedAssignments, timetableForm.planId]);

  const selectedClass = classOptions.find((c) => c.key === timetableForm.classKey);

  const loadDept = async () => {
    if (!teacherId) return "";
    const profile = await apiCall(buildUrl(`get_teacher_profile.php?id=${teacherId}`));
    if (profile.status && profile.teacher) {
      return profile.teacher.dept || "";
    }
    return "";
  };

  const loadData = async () => {
    setLoading(true);
    const deptValue = await loadDept();
    setDept(deptValue);

    const controllerRes = await apiCall(
      buildUrl(`get_subject_controller_status.php?teacher_id=${teacherId}`)
    );
    setIsController(Boolean(controllerRes.is_subject_controller));

    if (!deptValue) {
      setNotice("Department not found. Please re-login.");
      setLoading(false);
      return;
    }

    const [subjectsRes, classesRes, teachersRes, plansRes, assignmentsRes] = await Promise.all([
      apiCall(buildUrl(`list_subjects.php?dept=${encodeURIComponent(deptValue)}`)),
      apiCall(buildUrl(`get_department_classes.php?department=${encodeURIComponent(deptValue)}`)),
      apiCall(buildUrl(`get_department_teachers.php?department=${encodeURIComponent(deptValue)}`)),
      apiCall(buildUrl(`list_class_subject_plans.php?dept=${encodeURIComponent(deptValue)}`)),
      apiCall(buildUrl(`list_subject_staff_assignments.php?dept=${encodeURIComponent(deptValue)}`))
    ]);

    setSubjects(subjectsRes.status ? subjectsRes.subjects || [] : []);
    setClasses(classesRes.status ? classesRes.classes || [] : []);
    setTeachers(teachersRes.status ? teachersRes.teachers || [] : []);
    setPlans(plansRes.status ? plansRes.plans || [] : []);
    setAssignments(assignmentsRes.status ? assignmentsRes.assignments || [] : []);

    setLoading(false);
  };

  const loadTimetable = async (year, section) => {
    if (!year || !section) {
      setTimetable([]);
      return;
    }
    const data = await apiCall(
      buildUrl(
        `list_class_timetable.php?dept=${encodeURIComponent(dept)}&year=${year}&section=${encodeURIComponent(section)}`
      )
    );
    setTimetable(data.status ? data.timetable || [] : []);
  };

  useEffect(() => {
    loadData();
  }, []);

  useEffect(() => {
    if (selectedClass) {
      loadTimetable(selectedClass.year, selectedClass.section);
    }
  }, [selectedClass]);

  const handleSubjectCreate = async () => {
    setNotice("");
    const payload = {
      dept,
      year: newSubject.year,
      semester: newSubject.semester || null,
      subject_code: newSubject.subject_code,
      subject_name: newSubject.subject_name,
      credits: newSubject.credits
    };

    const res = await apiCall(buildUrl("create_subject.php"), {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify(payload)
    });

    setNotice(res.message || "");
    if (res.status) {
      setNewSubject({ year: "", semester: "", subject_code: "", subject_name: "", credits: "" });
      const subjectsRes = await apiCall(buildUrl(`list_subjects.php?dept=${encodeURIComponent(dept)}`));
      setSubjects(subjectsRes.status ? subjectsRes.subjects || [] : []);
    }
  };

  const handlePlan = async () => {
    setNotice("");
    const chosen = classOptions.find((c) => c.key === planForm.classKey);
    if (!chosen) {
      setNotice("Choose a class.");
      return;
    }

    const res = await apiCall(buildUrl("plan_class_subject.php"), {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({
        dept,
        year: chosen.year,
        section: chosen.section,
        subject_id: planForm.subjectId
      })
    });

    setNotice(res.message || "");
    if (res.status) {
      setPlanForm({ classKey: "", subjectId: "" });
      const plansRes = await apiCall(buildUrl(`list_class_subject_plans.php?dept=${encodeURIComponent(dept)}`));
      setPlans(plansRes.status ? plansRes.plans || [] : []);
    }
  };

  const handleAssignStaff = async () => {
    setNotice("");
    const selectedPlan = plans.find((plan) => String(plan.id) === String(assignForm.planId));
    if (!selectedPlan) {
      setNotice("Select a plan first.");
      return;
    }
    if (selectedPlan.status !== "approved") {
      setNotice("Plan must be approved by HOD before assigning staff.");
      return;
    }

    const res = await apiCall(buildUrl("assign_subject_staff.php"), {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({
        plan_id: assignForm.planId,
        teacher_id: assignForm.teacherId
      })
    });

    setNotice(res.message || "");
    if (res.status) {
      setAssignForm({ planId: "", teacherId: "" });
      const assignmentsRes = await apiCall(buildUrl(`list_subject_staff_assignments.php?dept=${encodeURIComponent(dept)}`));
      setAssignments(assignmentsRes.status ? assignmentsRes.assignments || [] : []);
    }
  };

  const handleTimetable = async () => {
    setNotice("");
    const chosen = classOptions.find((c) => c.key === timetableForm.classKey);
    if (!chosen) {
      setNotice("Choose a class.");
      return;
    }

    if (!timetableForm.planId || !timetableForm.teacherId) {
      setNotice("Select an approved plan and staff assignment.");
      return;
    }

    const eligible = timetableAssignments.some(
      (assignment) => String(assignment.teacher_id) === String(timetableForm.teacherId)
    );
    if (!eligible) {
      setNotice("Selected staff must be approved for this plan.");
      return;
    }

    const res = await apiCall(buildUrl("set_class_timetable.php"), {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({
        dept,
        year: chosen.year,
        section: chosen.section,
        day: timetableForm.day,
        period: timetableForm.period,
        plan_id: timetableForm.planId,
        teacher_id: timetableForm.teacherId
      })
    });

    setNotice(res.message || "");
    if (res.status) {
      const updated = await apiCall(
        buildUrl(
          `list_class_timetable.php?dept=${encodeURIComponent(dept)}&year=${chosen.year}&section=${encodeURIComponent(chosen.section)}`
        )
      );
      setTimetable(updated.status ? updated.timetable || [] : []);
    }
  };

  if (loading) {
    return <div className="card p-4 shadow">Loading...</div>;
  }

  if (!isController) {
    return (
      <div className="card p-4 shadow">
        <h3>Subject Controller</h3>
        <p className="text-muted">You are not assigned as a subject controller.</p>
        {notice && <div className="alert alert-warning">{notice}</div>}
      </div>
    );
  }

  return (
    <div className="container mt-3">
      <h3 className="mb-3">🧭 Subject Controller Workspace</h3>
      <p className="text-muted">All subject plans, staff assignments, and timetables need HOD approval.</p>
      {notice && <div className="alert alert-info">{notice}</div>}

      <div className="card p-4 shadow mb-4">
        <h5>📘 Subjects</h5>
        <div className="row g-2 align-items-end">
          <div className="col-md-2">
            <label className="form-label">Year</label>
            <input
              className="form-control"
              value={newSubject.year}
              onChange={(e) => setNewSubject({ ...newSubject, year: e.target.value })}
            />
          </div>
          <div className="col-md-2">
            <label className="form-label">Semester</label>
            <input
              className="form-control"
              value={newSubject.semester}
              onChange={(e) => setNewSubject({ ...newSubject, semester: e.target.value })}
            />
          </div>
          <div className="col-md-2">
            <label className="form-label">Code</label>
            <input
              className="form-control"
              value={newSubject.subject_code}
              onChange={(e) => setNewSubject({ ...newSubject, subject_code: e.target.value })}
            />
          </div>
          <div className="col-md-4">
            <label className="form-label">Subject Name</label>
            <input
              className="form-control"
              value={newSubject.subject_name}
              onChange={(e) => setNewSubject({ ...newSubject, subject_name: e.target.value })}
            />
          </div>
          <div className="col-md-2">
            <label className="form-label">Credits</label>
            <input
              className="form-control"
              value={newSubject.credits}
              onChange={(e) => setNewSubject({ ...newSubject, credits: e.target.value })}
            />
          </div>
        </div>
        <button className="btn btn-primary mt-3" onClick={handleSubjectCreate}>
          Save Subject
        </button>

        <div className="table-responsive mt-3">
          <table className="table table-sm table-striped">
            <thead>
              <tr>
                <th>Year</th>
                <th>Code</th>
                <th>Name</th>
                <th>Credits</th>
              </tr>
            </thead>
            <tbody>
              {subjects.map((s) => (
                <tr key={s.id}>
                  <td>{s.year}</td>
                  <td>{s.subject_code}</td>
                  <td>{s.subject_name}</td>
                  <td>{s.credits}</td>
                </tr>
              ))}
              {subjects.length === 0 && (
                <tr>
                  <td colSpan={4} className="text-center text-muted">
                    No subjects found.
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>

      <div className="card p-4 shadow mb-4">
        <h5>🗂️ Plan Subjects for Classes</h5>
        <div className="row g-2 align-items-end">
          <div className="col-md-4">
            <label className="form-label">Class</label>
            <select
              className="form-select"
              value={planForm.classKey}
              onChange={(e) => setPlanForm({ ...planForm, classKey: e.target.value })}
            >
              <option value="">Select class</option>
              {classOptions.map((c) => (
                <option key={c.key} value={c.key}>
                  {c.label}
                </option>
              ))}
            </select>
          </div>
          <div className="col-md-6">
            <label className="form-label">Subject</label>
            <select
              className="form-select"
              value={planForm.subjectId}
              onChange={(e) => setPlanForm({ ...planForm, subjectId: e.target.value })}
            >
              <option value="">Select subject</option>
              {subjects.map((s) => (
                <option key={s.id} value={s.id}>
                  {s.subject_code} - {s.subject_name}
                </option>
              ))}
            </select>
          </div>
        </div>
        <button className="btn btn-primary mt-3" onClick={handlePlan}>
          Plan Subject
        </button>

        <div className="table-responsive mt-3">
          <table className="table table-sm table-striped">
            <thead>
              <tr>
                <th>Class</th>
                <th>Subject</th>
                <th>Credits</th>
                <th>Status</th>
              </tr>
            </thead>
            <tbody>
              {plans.map((p) => (
                <tr key={p.id}>
                  <td>{`Year ${p.year} - ${p.section}`}</td>
                  <td>{`${p.subject_code} - ${p.subject_name}`}</td>
                  <td>{p.credits ?? "-"}</td>
                  <td>
                    <span
                      className={`badge ${
                        p.status === "approved"
                          ? "bg-success"
                          : p.status === "rejected"
                          ? "bg-danger"
                          : "bg-warning text-dark"
                      }`}
                    >
                      {p.status}
                    </span>
                  </td>
                </tr>
              ))}
              {plans.length === 0 && (
                <tr>
                  <td colSpan={4} className="text-center text-muted">
                    No plans created.
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>

      <div className="card p-4 shadow mb-4">
        <h5>👩‍🏫 Assign Subject Staff</h5>
        <div className="row g-2 align-items-end">
          <div className="col-md-6">
            <label className="form-label">Plan</label>
            <select
              className="form-select"
              value={assignForm.planId}
              onChange={(e) => setAssignForm({ ...assignForm, planId: e.target.value })}
              disabled={approvedPlans.length === 0}
            >
              <option value="">Select approved plan</option>
              {approvedPlans.map((p) => (
                <option key={p.id} value={p.id}>
                  {`Year ${p.year} - ${p.section} | ${p.subject_code}`}
                </option>
              ))}
            </select>
          </div>
          <div className="col-md-6">
            <label className="form-label">Teacher</label>
            <select
              className="form-select"
              value={assignForm.teacherId}
              onChange={(e) => setAssignForm({ ...assignForm, teacherId: e.target.value })}
            >
              <option value="">Select teacher</option>
              {teachers.map((t) => (
                <option key={t.id} value={t.id}>
                  {t.name}
                </option>
              ))}
            </select>
          </div>
        </div>
        <button className="btn btn-primary mt-3" onClick={handleAssignStaff}>
          Assign Staff
        </button>
        {approvedPlans.length === 0 && (
          <div className="text-muted small mt-2">No approved plans yet. Ask HOD to approve plans.</div>
        )}

        <div className="table-responsive mt-3">
          <table className="table table-sm table-striped">
            <thead>
              <tr>
                <th>Class</th>
                <th>Subject</th>
                <th>Credits</th>
                <th>Teacher</th>
                <th>Status</th>
              </tr>
            </thead>
            <tbody>
              {assignments.map((a) => (
                <tr key={a.id}>
                  <td>{`Year ${a.year} - ${a.section}`}</td>
                  <td>{`${a.subject_code} - ${a.subject_name}`}</td>
                  <td>{a.credits ?? "-"}</td>
                  <td>{a.teacher_name || "-"}</td>
                  <td>
                    <span
                      className={`badge ${
                        a.status === "approved"
                          ? "bg-success"
                          : a.status === "rejected"
                          ? "bg-danger"
                          : "bg-warning text-dark"
                      }`}
                    >
                      {a.status}
                    </span>
                  </td>
                </tr>
              ))}
              {assignments.length === 0 && (
                <tr>
                  <td colSpan={5} className="text-center text-muted">
                    No assignments yet.
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>

      <div className="card p-4 shadow mb-4">
        <h5>📅 Class Timetable</h5>
        <div className="row g-2 align-items-end">
          <div className="col-md-3">
            <label className="form-label">Class</label>
            <select
              className="form-select"
              value={timetableForm.classKey}
              onChange={(e) => setTimetableForm({ ...timetableForm, classKey: e.target.value })}
            >
              <option value="">Select class</option>
              {classOptions.map((c) => (
                <option key={c.key} value={c.key}>
                  {c.label}
                </option>
              ))}
            </select>
          </div>
          <div className="col-md-2">
            <label className="form-label">Day</label>
            <select
              className="form-select"
              value={timetableForm.day}
              onChange={(e) => setTimetableForm({ ...timetableForm, day: e.target.value })}
            >
              {dayOptions.map((d) => (
                <option key={d} value={d}>
                  {d}
                </option>
              ))}
            </select>
          </div>
          <div className="col-md-2">
            <label className="form-label">Period</label>
            <select
              className="form-select"
              value={timetableForm.period}
              onChange={(e) => setTimetableForm({ ...timetableForm, period: e.target.value })}
            >
              {[1, 2, 3, 4, 5, 6].map((p) => (
                <option key={p} value={p}>
                  {p}
                </option>
              ))}
            </select>
          </div>
          <div className="col-md-3">
            <label className="form-label">Plan</label>
            <select
              className="form-select"
              value={timetableForm.planId}
              onChange={(e) =>
                setTimetableForm({ ...timetableForm, planId: e.target.value, teacherId: "" })
              }
              disabled={approvedPlans.length === 0}
            >
              <option value="">Select approved plan</option>
              {approvedPlans.map((p) => (
                <option key={p.id} value={p.id}>
                  {`Year ${p.year} - ${p.section} | ${p.subject_code}`}
                </option>
              ))}
            </select>
          </div>
          <div className="col-md-2">
            <label className="form-label">Teacher</label>
            <select
              className="form-select"
              value={timetableForm.teacherId}
              onChange={(e) => setTimetableForm({ ...timetableForm, teacherId: e.target.value })}
              disabled={timetableAssignments.length === 0}
            >
              <option value="">Select approved staff</option>
              {timetableAssignments.map((a) => (
                <option key={a.id} value={a.teacher_id}>
                  {a.teacher_name || `Teacher ${a.teacher_id}`}
                </option>
              ))}
            </select>
          </div>
        </div>
        <button className="btn btn-primary mt-3" onClick={handleTimetable}>
          Save Timetable Entry
        </button>

        <div className="table-responsive mt-3">
          <table className="table table-sm table-striped">
            <thead>
              <tr>
                <th>Day</th>
                <th>Period</th>
                <th>Subject</th>
                <th>Credits</th>
                <th>Teacher</th>
                <th>Status</th>
              </tr>
            </thead>
            <tbody>
              {timetable.map((t) => (
                <tr key={t.id}>
                  <td>{t.day}</td>
                  <td>{t.period}</td>
                  <td>{`${t.subject_code} - ${t.subject_name}`}</td>
                  <td>{t.credits ?? "-"}</td>
                  <td>{t.teacher_name || "-"}</td>
                  <td>
                    <span
                      className={`badge ${
                        t.status === "approved"
                          ? "bg-success"
                          : t.status === "rejected"
                          ? "bg-danger"
                          : "bg-warning text-dark"
                      }`}
                    >
                      {t.status}
                    </span>
                  </td>
                </tr>
              ))}
              {timetable.length === 0 && (
                <tr>
                  <td colSpan={6} className="text-center text-muted">
                    No timetable entries.
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
}

import { useEffect, useState, useRef } from "react";
import QRCode from "qrcode";
import { apiCall, buildUrl } from "../utils/apiClient";

// QR Code Image Component
function QRCodeImage({ value, size = 160 }) {
  const canvasRef = useRef(null);

  useEffect(() => {
    if (canvasRef.current && value) {
      QRCode.toCanvas(canvasRef.current, value, { width: size }, (error) => {
        if (error) console.error("QR Error:", error);
      });
    }
  }, [value, size]);

  return <canvas ref={canvasRef} style={{ margin: "10px 0", border: "2px solid #28a745", borderRadius: "4px" }} />;
}

export default function TeacherAttendance(){

  // Login session check
  const savedUser = localStorage.getItem("user");
  const user = savedUser ? JSON.parse(savedUser) : null;
  const isAuthorized = !!user && (user.role === "teacher" || user.role === "hod");

  const teacher_id =
    user?.teacher_id ||
    user?.linked_id ||
    user?.user?.linked_id ||
    user?.user?.teacher_id ||
    user?.user?.user_id ||
    user?.user?.id ||
    user?.user_id ||
    user?.id;


  // State
  const [session,setSession] = useState(null);
  const [students,setStudents] = useState([]);
  const [absent,setAbsent] = useState([]);
  const [msg,setMsg] = useState("");

  const [summary,setSummary] = useState({
    total:0,
    present:0,
    absent:0,
    percentage:0
  });

  const [courses,setCourses] = useState([]);
  const [sel,setSel] = useState("");
  const [period, setPeriod] = useState("1");

  useEffect(() => {
    if(!savedUser){
      alert("Session expired. Please login again.");
      window.location.href = "/";
      return;
    }

    if(!isAuthorized){
      alert("Unauthorized! Only teachers and HODs allowed.");
      window.location.href = "/";
    }
  }, [savedUser, isAuthorized]);


  // Load courses
  const loadCourses = async ()=>{
    if (!teacher_id) return;

    try {
      const data = await apiCall(
        buildUrl(`get_teacher_courses.php?teacher_id=${teacher_id}`)
      );
      if(data.status) setCourses(data.courses || []);
    } catch(err) {
      console.error("Error loading courses:", err);
      setMsg("Failed to load courses. Check backend connection.");
    }
  };


  // Load active session
  const loadSession = async ()=>{
    if (!teacher_id) return;

    try {
      const data = await apiCall(
        buildUrl(`get_active_teacher_session.php?teacher_id=${teacher_id}`)
      );

      if(data.status){
        setSession(data.session);
        loadStudents(data.session.id);
        loadSummary(data.session.id);
        loadAbsent(data.session.id);
        setMsg("");
      } else {
        setSession(null);
        setStudents([]);
        setAbsent([]);
        setMsg("No Active Attendance Session");
      }
    } catch(err) {
      console.error("Error loading session:", err);
      setMsg("Failed to load session. Check backend connection.");
    }
  };


  // Load students with hotspot data
  const loadStudents = async (sid) => {
    try {
      const data = await apiCall(
        buildUrl(`get_attendance_list.php?session_id=${sid}`)
      );
      if (data.status) {
        setStudents(data.attendance || []);
      }
    } catch (err) {
      console.error("Error loading students:", err);
    }
  };

  // Summary
  const loadSummary = async (sid)=>{
    try {
      // Calculate summary from attendance_list data
      const data = await apiCall(
        buildUrl(`get_attendance_list.php?session_id=${sid}`)
      );
      if(data.status) {
        setSummary({
          total: data.stats?.total_students || 0,
          present: data.stats?.total_present || 0,
          absent: (data.stats?.total_students || 0) - (data.stats?.total_present || 0),
          percentage: Math.round(((data.stats?.total_present || 0) / (data.stats?.total_students || 1)) * 100),
          rejected_attempts: data.rejected_attempts || []
        });
      }
    } catch(err) {
      console.error("Error loading summary:", err);
    }
  };


  // Absent students
  const loadAbsent = async (sid)=>{
    try {
      const data = await apiCall(
        buildUrl(`get_attendance_list.php?session_id=${sid}`)
      );
      if(data.status) {
        const presentIds = new Set((data.attendance || []).map(s => s.student_id));
        const allStudents = data.all_students || [];
        const absentStudents = allStudents.filter(s => !presentIds.has(s.id));
        setAbsent(absentStudents);
      }
    } catch(err) {
      console.error("Error loading absent students:", err);
    }
  };


  // Auto refresh
  useEffect(()=>{
    if (!isAuthorized) return;

    loadSession();
    loadCourses();

    // Real-time polling every 2 seconds for live hotspot attendance updates
    const i = setInterval(()=>{
      if(session){
        loadStudents(session.id);
        loadSummary(session.id);
        loadAbsent(session.id);
      } else {
        loadSession();
      }
    }, 2000); // 2 second interval for real-time updates

    return ()=>clearInterval(i);
  },[session, isAuthorized]);

  if (!isAuthorized) {
    return null;
  }


  // Start session
  const startSession = async ()=>{

    if(!sel){
      alert("Select a class to start attendance");
      return;
    }

    const c = JSON.parse(sel);

    try {
      const data = await apiCall(buildUrl("start_attendance.php"), {
        method:"POST",
        headers:{ "Content-Type":"application/json"},
        body: JSON.stringify({
          teacher_id,
          subject: c.subject,
          dept: c.dept,
          year: c.year,
          section: c.section,
          period: Number(period)
        })
      });
      alert(data.message);
      loadSession();
    } catch(err) {
      console.error("Error starting session:", err);
      alert("Failed to start session");
    }
  };


  // End session
  const endSession = async ()=>{
    if(!window.confirm("End Attendance Session?")) return;

    try {
      const data = await apiCall(
        buildUrl(`end_attendance.php?teacher_id=${teacher_id}`)
      );
      alert(data.message);
      loadSession();
    } catch(err) {
      console.error("Error ending session:", err);
      alert("Failed to end session");
    }
  };


  return(
    <div className="container mt-4">
      <div className="card p-4 shadow">

        <h3>Teacher Attendance Control</h3>


        {/* NO SESSION */}
        {!session && (
          <>
            <p className="text-danger">{msg}</p>

            <div className="d-flex gap-2 flex-wrap">
              <select 
                className="form-control"
                style={{ maxWidth: "420px" }}
                onChange={e=>setSel(e.target.value)}
              >
                <option>Select Class</option>

                {courses.map((c,i)=>(
                  <option key={i} value={JSON.stringify(c)}>
                    {c.dept} | Year {c.year} | Sec {c.section} | {c.subject_code ? `${c.subject_code} - ` : ""}{c.subject} | Credits {c.credits ?? "-"}
                  </option>
                ))}
              </select>

              <select
                className="form-control"
                style={{ maxWidth: "160px" }}
                value={period}
                onChange={(e) => setPeriod(e.target.value)}
              >
                {[1,2,3,4,5,6].map((p) => (
                  <option key={p} value={p}>{`Period ${p}`}</option>
                ))}
              </select>
            </div>

            <button className="btn btn-primary mt-3" onClick={startSession}>
              Start Attendance
            </button>
          </>
        )}


        {/* ACTIVE SESSION */}
        {session && (
          <>
            <div className="d-flex justify-content-between align-items-start mb-3">
              <div className="flex-grow-1">
                <p><b>Subject:</b> {session.subject} {session.period ? `(Period ${session.period})` : ""}</p>
                <p><b>Department:</b> {session.dept} | Year {session.year} | {session.section}</p>
                <p><b>Started:</b> {session.started_at}</p>
                
                {/* HOTSPOT INFORMATION */}
                <div className="alert alert-info p-2 mt-2">
                  <small>
                    <b>🌐 Hotspot Status:</b> {session.hotspot_enabled ? "ENABLED ✓" : "DISABLED"}<br/>
                    <b>🔗 Gateway IP:</b> {session.gateway_ip}<br/>
                    <b>🛰️ Network Prefix:</b> {session.gateway_prefix}
                  </small>
                </div>

                {/* QR CODE TOKEN FOR ATTENDANCE */}
                {session.qr_token && (
                  <div className="alert alert-success p-3 mt-2">
                    <b>📱 Attendance Token (QR Code):</b>
                    <div className="mt-2 p-3 bg-white rounded border-2 text-center" style={{ borderColor: "#28a745" }}>
                      <QRCodeImage value={session.qr_token} size={160} />
                      <h4 style={{ fontFamily: "monospace", letterSpacing: "2px", marginBottom: "10px", marginTop: "10px" }}>
                        {session.qr_token}
                      </h4>
                      <small className="text-muted d-block">
                        Students can scan this QR code or manually enter the token above to mark attendance
                      </small>
                    </div>
                  </div>
                )}
              </div>

              <button className="btn btn-danger" onClick={endSession}>
                End Session
              </button>
            </div>

            <hr/>


            {/* SUMMARY */}
            <div className="row text-center mb-3">

              <div className="col-md-3">
                <div className="card p-3 shadow">
                  <h6>Total Students</h6>
                  <h2>{summary.total}</h2>
                </div>
              </div>

              <div className="col-md-3">
                <div className="card p-3 shadow text-success">
                  <h6>Present</h6>
                  <h2>{summary.present}</h2>
                </div>
              </div>

              <div className="col-md-3">
                <div className="card p-3 shadow text-danger">
                  <h6>Absent</h6>
                  <h2>{summary.absent}</h2>
                </div>
              </div>

              <div className="col-md-3">
                <div className="card p-3 shadow text-primary">
                  <h6>Percentage</h6>
                  <h2>{summary.percentage}%</h2>
                </div>
              </div>

              <div className="col-md-3">
                <div className="card p-3 shadow text-warning">
                  <h6>Rejected (Proxy)</h6>
                  <h2>{summary.rejected_attempts?.length || 0}</h2>
                </div>
              </div>

            </div>

            <hr/>


            {/* REJECTION ATTEMPTS (Network Verification Failures) */}
            {summary.rejected_attempts && summary.rejected_attempts.length > 0 && (
              <>
                <h5 className="text-warning">⚠️ Rejected Attendance Attempts ({summary.rejected_attempts.length})</h5>
                <p className="text-muted small">These students attempted to join but were not on the hotspot network (possible proxy attempts)</p>

                <table className="table table-bordered table-sm">
                  <thead className="table-warning">
                    <tr>
                      <th>Attempted Time</th>
                      <th>Student ID</th>
                      <th>Student IP</th>
                      <th>Reason</th>
                    </tr>
                  </thead>

                  <tbody>
                    {summary.rejected_attempts.map((attempt, i) => (
                      <tr key={i}>
                        <td>{attempt.attempted_at}</td>
                        <td>{attempt.student_id}</td>
                        <td>{attempt.student_ip}</td>
                        <td>
                          <small className="text-danger">
                            Network mismatch: {attempt.student_ip_prefix} ≠ {session.gateway_prefix}
                          </small>
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>

                <hr/>
              </>
            )}


            {/* PRESENT */}
            <h5>✓ Students Marked Present ({students.length})</h5>

            <table className="table table-bordered">
              <thead className="table-success">
                <tr>
                  <th>Reg No</th>
                  <th>Name</th>
                  <th>Dept</th>
                  <th>Marked Time</th>
                  <th>Network Status</th>
                </tr>
              </thead>

              <tbody>
                {students.map((s,i)=>(
                  <tr key={i} className="table-light">
                    <td>{s.reg_no}</td>
                    <td>{s.name}</td>
                    <td>{s.dept}</td>
                    <td>{s.marked_at}</td>
                    <td>
                      <span className="badge bg-success">✓ On Network</span>
                    </td>
                  </tr>
                ))}

                {students.length === 0 && (
                  <tr>
                    <td colSpan="5" className="text-center text-muted">
                      Waiting for students to join...
                    </td>
                  </tr>
                )}
              </tbody>
            </table>


            <hr/>


            {/* ABSENT */}
            <h5 className="text-danger">✗ Absent Students ({absent.length})</h5>

            <table className="table table-bordered">
              <thead className="table-danger">
                <tr>
                  <th>Reg No</th>
                  <th>Name</th>
                  <th>Dept</th>
                </tr>
              </thead>

              <tbody>

                {absent.map((s,i)=>(
                  <tr key={i} className="table-light">
                    <td>{s.reg_no}</td>
                    <td>{s.name}</td>
                    <td>{s.dept}</td>
                  </tr>
                ))}

                {absent.length === 0 && (
                  <tr>
                    <td colSpan="3" className="text-center text-success fw-bold">
                      ✓ All Students Present! 🎉
                    </td>
                  </tr>
                )}

              </tbody>
            </table>
          </>
        )}

      </div>
    </div>
  );
}

import { useEffect, useState } from "react";
import { apiCall, buildUrl } from "../utils/apiClient";

export default function TeacherBiometric(){
  const user = JSON.parse(localStorage.getItem("user"));
  const teacher_id =
    user?.teacher_id ||
    user?.linked_id ||
    user?.user?.linked_id ||
    user?.user?.teacher_id ||
    user?.user?.user_id ||
    user?.user?.id ||
    user?.user_id ||
    user?.id;

  const [logs, setLogs] = useState([]);
  const [message, setMessage] = useState("");
  const [note, setNote] = useState("");

  const loadLogs = async () => {
    if (!teacher_id) return;
    const data = await apiCall(buildUrl(`get_teacher_biometric.php?teacher_id=${teacher_id}`));
    if (data.status) setLogs(data.logs || []);
  };

  const logBiometric = async (status) => {
    if (!teacher_id) {
      setMessage("Teacher ID not found. Please log in again.");
      return;
    }
    const data = await apiCall(buildUrl("log_teacher_biometric.php"), {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ teacher_id, status, method: "BIOMETRIC", note })
    });
    setMessage(data.message || "Updated");
    setNote("");
    loadLogs();
  };

  useEffect(() => {
    loadLogs();
  }, [teacher_id]);

  return (
    <div className="card p-4 shadow">
      <h3>📍 Biometric Attendance</h3>

      {message && <div className="alert alert-info">{message}</div>}

      <div className="row g-2 align-items-end mb-3">
        <div className="col-md-8">
          <label className="form-label">Note (optional)</label>
          <input
            className="form-control"
            value={note}
            onChange={(e) => setNote(e.target.value)}
            placeholder="Remarks or device note"
          />
        </div>
        <div className="col-md-4 d-flex gap-2">
          <button className="btn btn-success w-100" onClick={() => logBiometric("CHECK_IN")}>Check In</button>
          <button className="btn btn-danger w-100" onClick={() => logBiometric("CHECK_OUT")}>Check Out</button>
        </div>
      </div>

      <div className="table-responsive">
        <table className="table table-striped">
          <thead>
            <tr>
              <th>Status</th>
              <th>Method</th>
              <th>Note</th>
              <th>Time</th>
            </tr>
          </thead>
          <tbody>
            {logs.map((log) => (
              <tr key={log.id}>
                <td>{log.status}</td>
                <td>{log.method}</td>
                <td>{log.note || "-"}</td>
                <td>{log.logged_at ? new Date(log.logged_at).toLocaleString() : "-"}</td>
              </tr>
            ))}
            {logs.length === 0 && (
              <tr>
                <td colSpan="4" className="text-center">No biometric logs yet.</td>
              </tr>
            )}
          </tbody>
        </table>
      </div>
    </div>
  );
}

import { useState, useEffect } from "react";
import { apiCall, buildUrl } from "../utils/apiClient";

function StatCard({ icon, title, value, color }) {
