import { useEffect, useState } from "react";
import { apiCall, buildUrl } from "../utils/apiClient";

export default function TeacherMarks(){
  const saved = localStorage.getItem("user");
  const user = saved ? JSON.parse(saved) : null;
  const isAuthorized = !!user;

  const [search, setSearch] = useState("");
  const [students, setStudents] = useState([]);
  const [selected, setSelected] = useState(null);
  const [marks, setMarks] = useState([]);

  useEffect(() => {
    if(!isAuthorized){
      window.location.href = "/";
    }
  }, [isAuthorized]);

  const searchStudents = async ()=>{
    try{
      const url = new URL(buildUrl("get_students_advanced.php"));
      if(search) url.searchParams.set("search", search);
      const data = await apiCall(url.toString());
      if(data.status) setStudents(data.students || []);
    }catch(e){ console.error(e); }
  };

  const loadMarks = async (student_id)=>{
    try{
      const data = await apiCall(buildUrl(`get_student_marks.php?student_id=${student_id}`));
      if(data.status) setMarks(data.marks || []);
    }catch(e){ console.error(e); }
  };

  useEffect(()=>{ if(selected) loadMarks(selected.id); },[selected]);

  if (!isAuthorized) {
    return null;
  }

  return (
    <div className="card p-4 shadow">
      <h3>🧪 View Student Marks</h3>

      <div className="mb-3 d-flex gap-2">
        <input className="form-control" placeholder="Search students by name or regno" value={search} onChange={e=>setSearch(e.target.value)} />
        <button className="btn btn-primary" onClick={searchStudents}>Search</button>
      </div>

      <div className="row">
        <div className="col-md-4">
          <h6>Students</h6>
          <ul className="list-group">
            {students.map(s=> (
              <li key={s.id} className={`list-group-item ${selected?.id===s.id? 'active' : ''}`} onClick={()=>setSelected(s)} style={{cursor:'pointer'}}>
                {s.reg_no} - {s.name}
              </li>
            ))}
            {students.length===0 && <li className="list-group-item">No students</li>}
          </ul>
        </div>

        <div className="col-md-8">
          <h6>Marks {selected ? `for ${selected.name}` : ''}</h6>
          {selected ? (
            <table className="table table-sm">
              <thead>
                <tr>
                  <th>Subject</th>
                  <th>Semester</th>
                  <th>CIA 1</th>
                  <th>CIA 2</th>
                  <th>CIA 3</th>
                  <th>Attendance</th>
                  <th>Total</th>
                </tr>
              </thead>
              <tbody>
                {marks.map((m)=>(
                  <tr key={m.id}>
                    <td>{m.subject}</td>
                    <td>{m.semester}</td>
                    <td>{m.cia1}</td>
                    <td>{m.cia2}</td>
                    <td>{m.cia3}</td>
                    <td>{m.attendance_mark}</td>
                    <td><b>{m.total}</b></td>
                  </tr>
                ))}
                {marks.length===0 && <tr><td colSpan={7}>No marks found</td></tr>}
              </tbody>
            </table>
          ) : (
            <p>Select a student to load marks.</p>
          )}
        </div>
      </div>
    </div>
  );
}

import { useEffect, useState } from "react";
import { useParams } from "react-router-dom";
import { apiCall, buildUrl } from "../utils/apiClient";

export default function TeacherProfile(){

  const { id } = useParams();
  const [t,setT] = useState(null);

  const load = async ()=>{
    if (!id) return;
    const data = await apiCall(
      buildUrl(`get_teacher_profile.php?id=${id}`)
    );
    if(data.status) setT(data.teacher);
  };

  useEffect(()=>{ load(); },[]);

  if(!t) return <h3 className="m-5">Loading...</h3>;

  return (
    <div className="container mt-4">

      <div className="card p-4 shadow">

        {/* Photo */}
        <div style={{textAlign:"center"}}>
          <img
                        src={
                          t.photo
                          ? buildUrl(`uploads/teachers/${t.photo}`)
                          : "https://cdn-icons-png.flaticon.com/512/149/149071.png"
                        }
            style={{
              width:"140px",
              height:"140px",
              borderRadius:"50%",
              objectFit:"cover",
              border:"3px solid #0d6efd"
            }}
          />
        </div>

        {/* Upload */}
        <input 
          type="file"
          className="form-control my-2"
          onChange={async (e)=>{

            const f = new FormData();
            f.append("id", id);
            f.append("photo", e.target.files[0]);

                        let res = await fetch(
                          buildUrl("upload_teacher_photo.php"),
                          { method:"POST", body:f }
                        );

                        let data = await res.json();
            alert(data.message);
            window.location.reload();
          }}
        />

        <h3 className="text-center">{t.name}</h3>

        <p><b>Staff ID:</b> {t.staff_id}</p>
        <p><b>Department:</b> {t.dept}</p>
        <p><b>Phone:</b> {t.phone}</p>
        <p><b>Email:</b> {t.email}</p>

      </div>

    </div>
  );
}

